-- в”Ђв”Ђ LiveChat в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Live chat and AI customer service platform from Text S.A. (formerly LiveChat Software), publicly traded on the Warsaw Stock Exchange. Separate company from LiveAgent.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (14-day free trial)$q$, pricing_model),
  starting_price = COALESCE($q$$19/month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2002, founded_year),
  company_size = COALESCE($q$~280 employees$q$, company_size),
  headquarters = COALESCE($q$WrocЕ‚aw, Poland$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Polish$q$]::text[],
  seo_title = COALESCE($q$LiveChat Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$LiveChat review covering features, pricing plans, company history as a public company, and how it differs from the unrelated LiveAgent platform.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$LiveChat is a live chat and customer service platform developed and sold by Text S.A., a publicly traded Polish company previously known as LiveChat Software S.A. It should not be confused with LiveAgent, the Slovakia-based help desk company built by Quality Unit; the two are separate, unrelated businesses that happen to have similar product names in the same market category. LiveChat Software was founded in 2002 in WrocЕ‚aw, Poland by Mariusz CiepЕ‚y, Maciej JarzД™bowski and Jakub Sitarz, but the company did not begin selling its product as a SaaS offering on the global market until 2010. Its ownership passed through several hands over the following decade: Capital Partners S.A. acquired a stake in 2006, that stake was later sold to Gadu-Gadu S.A., and the company was owned by GG Network, part of South Africa's Naspers Group, between 2008 and 2011, before the founders and management executed a buyout in 2011 to regain control. LiveChat Software went public on the Warsaw Stock Exchange in April 2014 under the ticker LVC, and in 2023 the parent company rebranded itself from LiveChat Software to Text to reflect a broader push into AI-driven customer service and e-commerce products, though the LiveChat product itself kept its name. Text is headquartered in WrocЕ‚aw, Poland, employs roughly 280 people, and reported trailing-twelve-month revenue of roughly 90 million dollars and annual recurring revenue approaching 90 million dollars as of mid-2026, making it one of the larger and more financially transparent companies in this category thanks to its public listing. The LiveChat product itself is a customer-facing chat widget paired with an agent-side inbox, and the company has increasingly layered AI into that inbox; its LiveChat 2.0 positioning highlights AI agents working alongside human agents inside a unified inbox, along with a built-in revenue-attribution counter that ties chat conversations to sales outcomes. Core capabilities include Text Intelligence analytics, visitor tracking, customizable chat widgets, canned responses, staffing and workload prediction tools, SMS and Apple Messages for Business channels on higher tiers, and reporting ranging from basic dashboards to advanced agent-performance analytics. LiveChat is also part of a broader product family from the same parent company, which separately sells ChatBot, a chatbot builder, and HelpDesk, a ticketing tool, giving Text a multi-product suite that customers can combine. Pricing is subscription-based with a 14-day free trial and no credit card required upfront. The Starter plan is priced at $19 per month billed annually for a single user and includes Text Intelligence, tracking of up to 100 visitors, one recurring campaign, 60 days of chat history and basic widget customization. The Team plan, at $49 per person per month annually, is aimed at full-time support teams and adds tracking of up to 400 visitors, unlimited campaigns, unlimited chat history, full widget customization and basic reporting. The Business plan, at $79 per person per month annually, targets dedicated customer service departments and adds tracking of up to 1,000 visitors, a work scheduler, staffing prediction, on-demand and advanced reporting, and SMS and Apple Messages for Business channels. An Enterprise plan offers custom pricing with white-label widgets, HIPAA compliance, SSO, dedicated onboarding and engineering support, and negotiable payment terms. LiveChat's customer base spans more than 35,000 companies globally, skewing toward e-commerce and mid-market customer service teams that want a polished, well-supported chat widget backed by a financially stable, publicly audited vendor. Its principal competitors include Intercom, Zendesk Chat, Tidio, Crisp and, in the help-desk-adjacent category, LiveAgent and Freshchat. LiveChat differentiates itself through its public-company transparency and stability, its integrated AI-plus-human inbox model, and its multi-product ecosystem of LiveChat, ChatBot and HelpDesk sold by the same parent, letting customers consolidate chat, automation and ticketing under one vendor relationship.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '00ba7518-5599-46d0-b82c-32563e1bac39';

