INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Intake Management$q$, $q$Dynamic questionnaires and client portals streamline capturing and qualifying new legal matters.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Matter Management$q$, $q$End-to-end case handling with configurable workflows and task automation.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Document Management$q$, $q$AI-assisted document generation paired with advanced PDF editing tools.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Time and Billing$q$, $q$Automated time capture and billing workflow optimization for legal teams.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Spend Management$q$, $q$Unified expense tracking, budgeting and invoice review, strengthened by the 2021 LegalStratus acquisition.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Reporting and Analytics$q$, $q$No-code reporting engine delivering real-time KPIs and firm-level insights.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Salesforce-Native Architecture$q$, $q$Built entirely on the Salesforce Platform, enabling AppExchange integrations and Salesforce Agentforce AI tooling.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Multi Practice-Area Configurability$q$, $q$Configurable to support 15-plus legal practice areas from personal injury to corporate legal operations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Deep Salesforce integration unifies legal operations with existing CRM and business systems$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$No-code reporting engine reduces reliance on developers for custom dashboards$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Broad functional coverage spanning intake through billing in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Strong fit for high-volume intake practices like personal injury and insurance defense$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Backed by institutional funding and an established enterprise legal customer base$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$No published self-serve pricing, requiring a sales demo before cost is known$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Salesforce-based implementations typically involve longer onboarding than lightweight standalone tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$May be costly and complex for solo practitioners or very small firms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Total cost of ownership can include separate Salesforce platform licensing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Firms without existing Salesforce experience face a steeper learning curve$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$What is Litify?$q$, $q$Litify is a legal operating platform built on the Salesforce Platform that helps law firms and corporate legal departments manage intake, matters, documents, billing and reporting in one system.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Is Litify built on Salesforce?$q$, $q$Yes, Litify runs natively on the Salesforce Platform, inheriting its CRM, security and integration infrastructure along with the AppExchange ecosystem.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$How much does Litify cost?$q$, $q$Litify does not publish self-serve pricing. Cost is quote-based and depends on user count, Salesforce license tier and implementation scope, available after a sales demo.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Who uses Litify?$q$, $q$Litify is used by law firms across 15-plus practice areas, notably personal injury and insurance defense firms, as well as corporate legal departments at large enterprises.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$How does Litify differ from Clio or MyCase?$q$, $q$Unlike Clio or MyCase, which are standalone SaaS practice management tools with self-serve pricing, Litify is built on Salesforce and generally targets larger firms and legal departments needing deeper customization.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Did Litify make any acquisitions?$q$, $q$Yes, Litify acquired e-billing vendor LegalStratus in 2021 to strengthen its spend management and billing capabilities.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$High-volume personal injury intake$q$, $q$Personal injury firms use Litify's dynamic intake questionnaires and client portals to standardize and speed up case qualification across large volumes of incoming leads.$q$, $q$Personal injury and mass-tort law firms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Corporate legal department operations$q$, $q$In-house legal teams at large enterprises use Litify to track matters, manage outside counsel spend, and report on legal department KPIs within their existing Salesforce environment.$q$, $q$Corporate legal departments$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Insurance defense case management$q$, $q$Insurance defense practices use Litify's matter management and billing tools to manage high case volumes with standardized workflows and automated time capture.$q$, $q$Insurance defense law firms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$Custom / Enterprise$q$, $q$Custom pricing (demo required)$q$, $q$Contact sales$q$, NULL, $q$["Intake management with dynamic questionnaires and client portals","Matter management with workflow automation","AI-assisted document generation and management","Time and billing automation","Spend and e-billing management","No-code reporting and analytics"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Litify is a legal operating platform built on the Salesforce Platform, founded in 2016 and headquartered in New York City. It helps law firms and corporate legal departments manage intake, matter workflows, documents, billing and reporting in a single connected system.$q$, $q$Because it runs natively on Salesforce, Litify inherits Salesforce's CRM data model, security architecture and AppExchange integration ecosystem, distinguishing it from most standalone legal practice management tools built on proprietary stacks.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Litify's core modules cover intake management with dynamic questionnaires and client portals, matter management with automated case workflows, AI-assisted document generation, automated time and billing, spend and e-billing management, and a no-code reporting engine for firm-level KPIs.$q$, $q$The platform serves more than 15 practice areas, with particular strength in personal injury and insurance defense firms handling high intake volumes, as well as corporate legal departments at large enterprises.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dc263e36-ce97-42d4-be53-04c312ae1484', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Litify does not publish self-serve pricing. Interested organizations must request a demo, and cost is determined by a custom quote based on user count, Salesforce license tier and implementation scope.$q$, $q$This quote-based model is typical of Salesforce-native enterprise software and contrasts with standalone competitors like Clio or MyCase, which publish flat per-user monthly pricing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Cookieless Tracking$q$, $q$Collects anonymous, aggregate usage data without cookies, IP storage or personally identifiable information.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$AI-Powered Reports$q$, $q$One-click AI-generated reports summarize web, product, SEO and marketing performance.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Funnel Analysis$q$, $q$Custom event tracking and conversion funnel creation for product and marketing analytics.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Real-Time Dashboards$q$, $q$Live visitor and performance metrics updated as traffic happens.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Multi-Domain Workspaces$q$, $q$Consolidate analytics across multiple client sites or projects in one account.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Shareable Client Reports$q$, $q$Branded, shareable reports designed for client or stakeholder distribution.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Self-Hosting Option$q$, $q$Open-source, Docker-deployable self-hosted version for full data ownership.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Fast Setup$q$, $q$Claims under-30-second onboarding via a single script tag, with no consent banner required.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Cookieless and GDPR-compliant by design, avoiding consent-banner overhead$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$AI-generated reports save time for agencies producing recurring client summaries$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Both hosted and self-hosted deployment options available$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Very fast, low-friction setup compared to Google Analytics$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Competitive, transparent pricing for small sites and agencies$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Very young company founded in late 2024, with limited operating track record$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Small team of under 10 employees may limit support responsiveness at scale$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Feature set is less mature than long-established analytics platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Pageview-based pricing tiers can become costly for high-traffic sites$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Some advanced product-analytics features lag behind dedicated tools like PostHog$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$What is Litlyx?$q$, $q$Litlyx is a cookieless, GDPR-compliant web analytics platform offering AI-generated reports as a privacy-friendly alternative to Google Analytics.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Is Litlyx the same as Litify?$q$, $q$No. Litlyx is a web analytics tool and Litify is an unrelated Salesforce-based legal practice management platform; the similar names are coincidental.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Can Litlyx be self-hosted?$q$, $q$Yes, Litlyx offers a free, open-source, Docker-deployable self-hosted version alongside its hosted cloud plans.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Does Litlyx require a cookie consent banner?$q$, $q$No, because Litlyx does not use cookies or store personally identifiable information, most sites can avoid a cookie consent banner for analytics purposes.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$How much does Litlyx cost?$q$, $q$Hosted plans start at EUR 8.99 per month for 10,000 monthly pageviews, rising to EUR 29.99 per month for 350,000 pageviews; self-hosting is free.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Who founded Litlyx?$q$, $q$Litlyx was founded in October 2024 by Antonio Verdiglione and is based in Rome, Italy, with backing from the Techstars Transformative World Torino accelerator.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Agency multi-client reporting$q$, $q$Digital agencies use Litlyx's multi-workspace support and AI-generated reports to manage analytics for many client sites and produce branded client reports quickly.$q$, $q$Digital marketing and web agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Privacy-first GA4 replacement$q$, $q$Small and mid-size businesses migrate from Google Analytics to Litlyx to achieve GDPR compliance and skip cookie consent banners.$q$, $q$Privacy-conscious small and mid-size businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Self-hosted analytics for developers$q$, $q$Developers deploy the open-source Docker version of Litlyx to keep full control of visitor data on their own infrastructure at no cost.$q$, $q$Developers and privacy-focused technical teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Mini$q$, $q$EUR 8.99/month$q$, $q$Annual$q$, NULL, $q$["10,000 monthly pageviews","1 workspace","Limited AI features","No client reports"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Basic$q$, $q$EUR 14.99/month$q$, $q$Annual$q$, NULL, $q$["100,000 monthly pageviews","Unlimited domains","Around 50 AI messages per month","Basic client reports"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Pro$q$, $q$EUR 29.99/month$q$, $q$Annual$q$, NULL, $q$["350,000 monthly pageviews","2 workspaces","200 AI messages per month","Custom reports","1 additional team member"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source Docker deployment","Full data ownership","No pageview limits imposed by vendor"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Litlyx is a cookieless, GDPR-compliant web analytics platform founded in October 2024 by Antonio Verdiglione and headquartered in Rome, Italy, backed by Techstars Transformative World Torino.$q$, $q$It should not be confused with Litify, a Salesforce-based legal practice management platform; the two are unrelated products with similar names.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Litlyx offers cookieless tracking, AI-generated one-click reports, custom event and funnel tracking, real-time dashboards, multi-domain workspace management and shareable client-ready reports.$q$, $q$It is available as both a hosted cloud product and a self-hosted, Docker-deployable open-source option, with over 1,700 GitHub stars on its public repository.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Litlyx's hosted plans are billed annually by monthly pageview volume: Mini at EUR 8.99/month for 10,000 pageviews, Basic at EUR 14.99/month for 100,000 pageviews, and Pro at EUR 29.99/month for 350,000 pageviews.$q$, $q$Self-hosting via Docker is completely free for teams willing to manage their own infrastructure and data.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bcaaafb7-ce4e-47a5-9712-f545552b12e7', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Voice, Video and Screen Share$q$, $q$Built-in real-time voice calls, video calls and screen sharing without third-party add-ons.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Multi-Channel Messaging$q$, $q$Native integration with Telegram, Facebook Messenger, WhatsApp via Twilio and SMS.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$AI Bot Integrations$q$, $q$Connects to OpenAI ChatGPT, Rasa, DeepPavlov, Ollama and Google Gemini for automated chatbots.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Unlimited Self-Hosted Usage$q$, $q$No caps on operators, concurrent chats or departments in the free self-hosted version.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Mobile Apps$q$, $q$Native iOS and Android apps let agents respond to chats from mobile devices.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Visitor Tracking and Co-Browsing$q$, $q$Detailed visitor tracking plus co-browsing and speech-to-text for richer support sessions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Plugin and MVC Architecture$q$, $q$PHP/MySQL MVC codebase supports custom plugins and deep customization.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Managed Cloud Hosting$q$, $q$Optional paid hosting and commercial support for teams that do not want to self-host.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Free and fully open source with no artificial feature or seat caps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Bundles voice, video and screen share that competitors often charge extra for$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Strong data control appeals to regulated industries like banking and healthcare$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Actively maintained with frequent releases since the early 2010s$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Extensive AI chatbot integrations including major LLM providers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Self-hosting requires managing PHP/MySQL server infrastructure and updates$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Interface and setup are less polished than modern commercial SaaS competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Smaller community and ecosystem than larger open-source projects like Chatwoot$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Documentation can be less comprehensive than well-funded commercial vendors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Managed cloud hosting option has less brand recognition than mainstream SaaS chat tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Is Live Helper Chat free?$q$, $q$Yes, the self-hosted software is free and open source with no caps on operators, concurrent chats or departments; paid managed cloud hosting and support are optional.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$What technology is Live Helper Chat built on?$q$, $q$It is built on a PHP and MySQL stack using an MVC architecture, making it deployable on standard LAMP infrastructure.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Does Live Helper Chat support AI chatbots?$q$, $q$Yes, it integrates with OpenAI ChatGPT, Rasa, DeepPavlov, Ollama and Google Gemini for building automated or AI-assisted chat responses.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Who created Live Helper Chat?$q$, $q$It was created by Lithuanian developer Remigijus Kiminas, who maintains the project under the handle remdex.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Can Live Helper Chat handle high volumes of chats?$q$, $q$Yes, in production it has demonstrated handling over 10,000 chats per day across dozens of concurrently active operators.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Does Live Helper Chat support voice and video calls?$q$, $q$Yes, it includes built-in voice calls, video calls and screen sharing alongside standard text chat.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Regulated-industry self-hosted support$q$, $q$Banks, healthcare organizations and universities self-host Live Helper Chat to keep customer conversation data fully on infrastructure they control.$q$, $q$Banks, healthcare providers and universities$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$AI chatbot-assisted support$q$, $q$Support teams connect Live Helper Chat to OpenAI or other LLM providers to build automated chatbots that handle routine inquiries before escalating to human agents.$q$, $q$Support teams adopting AI-assisted service$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$High-volume enterprise deployments$q$, $q$Organizations with dozens of concurrent support operators use the unlimited self-hosted tier to scale without per-seat licensing costs.$q$, $q$Enterprises with large support teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited operators, chats and departments","Voice, video and screen share","AI bot integrations","Requires own PHP/MySQL server"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$Managed Cloud Hosting$q$, $q$Custom pricing (contact for quote)$q$, $q$Subscription$q$, NULL, $q$["Fully hosted by the Live Helper Chat team","Commercial support included","No server maintenance required"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Live Helper Chat is an open-source live chat and customer support platform created by Lithuanian developer Remigijus Kiminas, with public releases dating back to at least 2013 and continuous active development since.$q$, $q$Built on a PHP and MySQL MVC architecture, it is self-hostable on standard LAMP infrastructure or available through managed cloud hosting from the project team.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform bundles voice calls, video calls, screen sharing, co-browsing and speech-to-text alongside standard chat, and integrates with Telegram, Facebook Messenger, WhatsApp and SMS.$q$, $q$Recent development has focused on AI bot integrations including OpenAI ChatGPT, Rasa, DeepPavlov, Ollama and Google Gemini for automated and AI-assisted responses.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core self-hosted software is free and open source, with no artificial caps on operators, concurrent chats or departments, an unusual stance in a market that typically gates these behind paid tiers.$q$, $q$Revenue comes from optional managed cloud hosting and paid commercial support for organizations that prefer not to run their own servers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('593f4d82-8400-4cbe-bca8-aa39046b2d53', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$One-Click Local Server$q$, $q$Start or stop a local dev server instantly from the VS Code status bar Go Live button.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Automatic Live Reload$q$, $q$Browser reloads automatically, or CSS hot-injects, whenever a watched file is saved.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$WebSocket-Based Sync$q$, $q$Uses a WebSocket channel between the editor and browser to push reload events in real time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Configurable Server Settings$q$, $q$Customizable port, server root, HTTPS and CORS support.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Multi-Root Workspace Support$q$, $q$Works across multi-root VS Code workspaces for larger projects.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Remote LAN Preview$q$, $q$Accessible over a local network for testing on phones and tablets on the same WiFi.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Dynamic Page Support via Companion Extension$q$, $q$Live Server Web Extension adds live reload for PHP, Node.js and ASP.NET backends.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Zero Configuration Setup$q$, $q$Works immediately after installation with no build tooling or config files required.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Completely free and open source under the MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Extremely popular with over 80 million installs and strong reviews$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Zero configuration required, ideal for beginners and quick prototyping$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Lightweight compared to full bundler-based dev servers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Supports HTTPS, CORS and remote network access for mobile testing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Not suited to modern component-based frameworks needing hot module replacement$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$No built-in bundling, transpiling or dependency management$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Maintained as a side project, so update cadence can be inconsistent$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Overlaps with Microsoft's own bundled Live Preview extension, causing some confusion$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Dynamic backend support requires installing a separate companion browser extension$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$What does the Live Server VS Code extension do?$q$, $q$It launches a local development server and automatically reloads the browser whenever a watched HTML, CSS or JavaScript file is saved.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Is Live Server free?$q$, $q$Yes, Live Server is completely free and open source under the MIT license.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Who created Live Server?$q$, $q$It was created by Indian developer Ritwick Dey and first published to the VS Code Marketplace in June 2017.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$How do you start Live Server?$q$, $q$Click Go Live in the VS Code status bar, right-click an HTML file and choose Open with Live Server, or use the command palette or keyboard shortcuts.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Does Live Server work with dynamic pages like PHP or Node.js?$q$, $q$The core extension serves static files; dynamic backend live reload requires the companion Live Server Web Extension browser extension.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$What are alternatives to Live Server?$q$, $q$Alternatives include Microsoft's built-in Live Preview extension, the community fork Five Server, and framework-native dev servers like Vite or webpack-dev-server.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Learning HTML, CSS and JavaScript$q$, $q$Students and coding bootcamp learners use Live Server to see instant visual feedback while working through web development tutorials.$q$, $q$Students and beginner web developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Static site prototyping$q$, $q$Front-end developers use Live Server to quickly prototype static HTML/CSS layouts without setting up a full build pipeline.$q$, $q$Front-end developers and designers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Quick local testing across devices$q$, $q$Developers use Live Server's remote LAN access to preview a page on a phone or tablet during responsive design testing.$q$, $q$Web developers testing responsive designs$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Local dev server with live reload","Configurable port, HTTPS and CORS","Multi-root workspace support","Remote LAN access"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Live Server is a free VS Code extension created by Ritwick Dey and first published in June 2017. It launches a local development server with automatic browser reload whenever a watched file is saved.$q$, $q$With over 80 million installs and a 4.5-star rating, it is one of the most widely used extensions in the VS Code Marketplace, particularly popular among students and front-end beginners.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Live Server uses a WebSocket connection to push reload or CSS hot-injection events to the browser the instant a file changes, started with a single click from the status bar or a keyboard shortcut.$q$, $q$It supports configurable ports, HTTPS, CORS, multi-root workspaces and remote LAN access, with a companion browser extension enabling live reload for dynamic PHP, Node.js and ASP.NET pages.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Live Server is entirely free and distributed under the MIT license as an open-source project with no paid tiers, subscriptions or in-app purchases.$q$, $q$It is maintained by its original creator alongside community contributors, with no company or commercial entity behind it.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2edbef47-7fcd-4c70-9580-9d209cf6882c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Omnichannel Ticketing Inbox$q$, $q$Unifies email, chat, voice and social messages into one shared inbox for agents.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Live Chat Widget$q$, $q$Real-time website chat with proactive invitations and customizable widgets.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Call Center and IVR$q$, $q$Built-in voice support with interactive voice response on Medium tier and above.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Knowledge Base and Customer Portal$q$, $q$Self-service help center and portal to deflect routine tickets.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Automation and SLA Rules$q$, $q$Automation rules, time-based triggers and service-level agreement enforcement.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$AI Answer Assistant and Chatbot$q$, $q$AI-powered response suggestions and chatbot automation included on plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Social and Messaging Channels$q$, $q$Facebook, Instagram, X, Viber, Telegram and WhatsApp integrations on higher tiers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Reporting and Agent Analytics$q$, $q$Performance reporting, agent ratings and audit logs for larger teams.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Broad feature set bundling ticketing, chat, call center and social in one price$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$API access and integrations included on every plan with no extra fees$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$30-day free trial with no credit card required$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Long operating history since 2004 reflects mature, well-tested platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Positioned as a lower-cost alternative to Zendesk and Freshdesk$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$No permanent free plan, only a time-limited trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Per-agent pricing can scale up quickly for larger support teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Advanced features like SSO and audit logs require higher-priced tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Frequently confused with the unrelated company LiveChat due to similar naming$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Interface can feel feature-dense compared to simpler chat-only tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$What is LiveAgent?$q$, $q$LiveAgent is a multi-channel help desk and live chat platform from Quality Unit that unifies email, chat, voice and social support into one ticketing system.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Is LiveAgent the same company as LiveChat?$q$, $q$No. LiveAgent is made by Quality Unit in Bratislava, Slovakia, while LiveChat is made by Text S.A. in WrocЕ‚aw, Poland; they are separate, unrelated companies.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$How much does LiveAgent cost?$q$, $q$Plans start around $15 per agent per month billed annually for Small Business, rising to around $69 per agent per month for Enterprise.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Does LiveAgent offer a free trial?$q$, $q$Yes, LiveAgent offers a 30-day free trial on all plans with no credit card required.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$When was LiveAgent founded?$q$, $q$Quality Unit, the company behind LiveAgent, was founded in 2004 in Bratislava, Slovakia; the help desk product was substantially overhauled in 2011.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$What are LiveAgent's main competitors?$q$, $q$Main competitors include Zendesk, Freshdesk, Help Scout, Zoho Desk and LiveChat.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$All-in-one SMB support desk$q$, $q$Small and mid-size businesses use LiveAgent to combine email, chat and phone support in one affordable ticketing system instead of paying for multiple point tools.$q$, $q$Small and mid-size business support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Multi-channel social support$q$, $q$E-commerce and consumer brands use LiveAgent to manage Facebook, Instagram, WhatsApp and Telegram support alongside traditional email tickets.$q$, $q$E-commerce and consumer brands$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Call center plus digital support$q$, $q$Support teams needing phone-based service use LiveAgent's built-in call center and IVR alongside chat and ticketing.$q$, $q$Support teams requiring integrated voice support$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Small Business$q$, $q$$15/agent/month$q$, $q$Annual$q$, NULL, $q$["Ticketing and live chat","Knowledge base and customer portal","Contact forms and automation rules","AI Answer Assistant and AI chatbot"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Medium Business$q$, $q$$29/agent/month$q$, $q$Annual$q$, NULL, $q$["Everything in Small Business","Call center and IVR","Time-based automation rules","Reporting and proactive chat","Service level agreements"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Large Business$q$, $q$$49/agent/month$q$, $q$Annual$q$, NULL, $q$["Everything in Medium Business","Single sign-on (SSO)","Custom agent roles and time tracking","Audit log","Facebook, Instagram, X, Viber, Telegram and WhatsApp"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$Enterprise$q$, $q$$69/agent/month$q$, $q$Annual$q$, NULL, $q$["Everything in Large Business","Dedicated account manager","Priority support","Assisted channel integration","Custom branding"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LiveAgent is a multi-channel help desk and live chat platform built by Quality Unit, founded in 2004 in Bratislava, Slovakia by Andrej Harsani and Viktor Zeman.$q$, $q$It is a separate and unaffiliated company and product from LiveChat, the similarly named Polish live chat company; the two are frequently confused but have no corporate relationship.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$LiveAgent unifies email, live chat, call center/IVR and social and messaging channels into a single shared ticketing inbox with over 175 claimed features.$q$, $q$It includes a knowledge base, customer portal, automation rules, SLA enforcement, agent performance reporting and AI-powered answer assistance and chatbots.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('861123b5-2ddd-4c46-aa4f-eb2c58a34c58', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$LiveAgent uses per-agent monthly subscription pricing across four tiers, from Small Business at around $15/agent/month up to Enterprise at around $69/agent/month, all billed annually with a 30-day free trial.$q$, $q$API access and integrations are included in every tier at no extra cost, unlike some competitors that charge separately for these.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$AI-Plus-Human Inbox$q$, $q$Unified inbox where AI agents and human agents work together on customer conversations.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Text Intelligence Analytics$q$, $q$Built-in analytics and revenue-attribution counter tying chats to sales outcomes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Customizable Chat Widget$q$, $q$Fully brandable chat widget with visitor tracking and targeted campaigns.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Staffing and Workload Prediction$q$, $q$Predicts staffing needs and schedules agents based on projected chat volume.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Multi-Channel Messaging$q$, $q$SMS and Apple Messages for Business channels available on higher tiers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Advanced Reporting$q$, $q$On-demand and advanced reporting with agent performance metrics.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Multi-Product Ecosystem$q$, $q$Integrates with sibling products ChatBot and HelpDesk from the same parent company.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Enterprise Security and Compliance$q$, $q$SSO, HIPAA compliance and white-label widgets available on the Enterprise plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Backed by a publicly traded, financially transparent parent company$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Integrated AI-plus-human inbox with revenue attribution$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Part of a multi-product suite (LiveChat, ChatBot, HelpDesk)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Trusted by over 35,000 companies with 24/7/365 support$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Clear per-person pricing tiers with a no-credit-card free trial$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Per-person pricing on Team and Business tiers can get expensive for larger teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Visitor tracking limits on lower tiers may be restrictive for high-traffic sites$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Enterprise features like HIPAA compliance and SSO require custom Enterprise pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Frequently confused with the unrelated company LiveAgent due to similar naming$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Advanced reporting and staffing prediction are gated behind the Business tier$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$What is LiveChat?$q$, $q$LiveChat is a live chat and AI customer service platform made by Text S.A., a publicly traded Polish company formerly known as LiveChat Software.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Is LiveChat the same company as LiveAgent?$q$, $q$No. LiveChat is made by Text S.A. in WrocЕ‚aw, Poland, while LiveAgent is made by Quality Unit in Bratislava, Slovakia; they are separate, unrelated companies.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$When was LiveChat founded?$q$, $q$LiveChat Software was founded in 2002 in WrocЕ‚aw, Poland, though it did not launch its global SaaS product until 2010.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Is LiveChat a public company?$q$, $q$Yes, LiveChat Software (now Text S.A.) has been listed on the Warsaw Stock Exchange under the ticker LVC since April 2014.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$How much does LiveChat cost?$q$, $q$Plans start at $19/month for Starter and go up to $79/person/month for Business, billed annually, with custom Enterprise pricing above that.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$What other products does Text S.A. sell besides LiveChat?$q$, $q$Text S.A. also sells ChatBot, a chatbot builder, and HelpDesk, a ticketing tool, alongside LiveChat.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$E-commerce sales-driven chat$q$, $q$Online retailers use LiveChat's revenue-attribution counter and AI-plus-human inbox to tie live chat conversations directly to sales outcomes.$q$, $q$E-commerce and online retail businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Dedicated customer service departments$q$, $q$Larger customer service teams use LiveChat's Business plan for staffing prediction, advanced reporting and SMS/Apple Messages for Business support.$q$, $q$Mid-market customer service departments$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Regulated enterprise support$q$, $q$Enterprises needing HIPAA compliance and SSO use LiveChat's Enterprise plan with white-label widgets and dedicated onboarding.$q$, $q$Enterprises in regulated industries$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Starter$q$, $q$$19/month$q$, $q$Annual (1 user)$q$, NULL, $q$["Text Intelligence analytics","Tracks up to 100 visitors","1 recurring campaign","60-day chat history","Basic widget customization"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Team$q$, $q$$49/person/month$q$, $q$Annual$q$, NULL, $q$["Everything in Starter","Tracks up to 400 visitors","Unlimited campaigns and chat history","Full widget customization","Basic reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Business$q$, $q$$79/person/month$q$, $q$Annual$q$, NULL, $q$["Everything in Team","Tracks up to 1,000 visitors","Work scheduler and staffing prediction","Advanced reporting","SMS and Apple Messages for Business"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Contact sales$q$, NULL, $q$["Custom tracking limits","White-label widget","SSO and HIPAA compliance","Dedicated onboarding and support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LiveChat is a live chat and AI customer service platform made by Text S.A. (formerly LiveChat Software S.A.), a Polish company founded in 2002 and publicly traded on the Warsaw Stock Exchange since 2014.$q$, $q$It is a separate, unrelated company from LiveAgent, the Slovakia-based help desk vendor; despite similar names the two have no corporate connection.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$LiveChat combines a customer-facing chat widget with an AI-plus-human agent inbox, Text Intelligence analytics, visitor tracking, staffing prediction and a revenue-attribution counter.$q$, $q$It is part of a broader product suite from the same parent company that also includes ChatBot and HelpDesk, letting customers consolidate chat, automation and ticketing.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00ba7518-5599-46d0-b82c-32563e1bac39', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$LiveChat is priced per person per month with a 14-day free trial, starting at $19/month for Starter and rising to $79/person/month for Business, with custom Enterprise pricing above that.$q$, $q$Higher tiers add visitor tracking limits, staffing prediction, advanced reporting, SMS/Apple Messages for Business, white labeling and HIPAA compliance.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Fully Browser-Based$q$, $q$No downloads or plugins required for hosts or attendees, running entirely in the browser.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Registration and Landing Pages$q$, $q$Built-in landing page builder and automated email reminder and follow-up sequences.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Live Captioning and Transcription$q$, $q$Real-time automatic transcription of spoken content during live sessions.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$AI Content Repurposing$q$, $q$Extracts webinar transcript content and reformats it for reuse across marketing channels.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Engagement Tools$q$, $q$Chat, polls, Q&A, emoji reactions and stage invitations to bring attendees on screen.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$On-Demand and Recorded Events$q$, $q$Supports live, on-demand and pre-recorded event formats with instant replays.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$CRM and Marketing Integrations$q$, $q$Connects to HubSpot and Zapier broadly, and Salesforce, Marketo, Pardot and Microsoft Dynamics on Enterprise.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Compliance and Security$q$, $q$GDPR compliant and ISO 27001 certified infrastructure.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$No downloads or plugins needed for hosts or attendees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Bundles the full webinar funnel from registration to post-event analytics$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Attendee-credit pricing can be efficient for occasional large events$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Permanent free plan available for evaluation and small use cases$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$GDPR compliance and ISO 27001 certification appeal to enterprise buyers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Free plan is limited to 20 minutes and 30 attendees, unsuitable for production use$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Attendee-credit pricing model can be confusing compared to flat monthly tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Enterprise-grade CRM integrations require the custom-priced Enterprise plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Costs can scale quickly for organizations running frequent high-attendance events$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Session length caps on Pro (4 hours) may be limiting for longer events$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$What is Livestorm?$q$, $q$Livestorm is a browser-based webinar and video engagement platform for hosting live, on-demand and recorded events without downloads.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Does Livestorm have a free plan?$q$, $q$Yes, Livestorm offers a permanent free plan limited to 20-minute sessions and 30 attendees, intended for evaluation.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$How does Livestorm pricing work?$q$, $q$Paid plans use an attendee-credit model where organizations purchase credits annually, and one credit is consumed per unique participant per session within a 12-month period.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$How many attendees can Livestorm support?$q$, $q$The Pro and Enterprise plans support up to 3,000 live attendees per event.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Does Livestorm require software downloads?$q$, $q$No, Livestorm runs entirely in the browser for both hosts and attendees, with no plugins or downloads required.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Who founded Livestorm?$q$, $q$Livestorm was founded in 2016 by Gilles Bertaux and is headquartered in Paris, France.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$B2B marketing webinars$q$, $q$Marketing teams use Livestorm to run lead-generation webinars with registration pages, automated email sequences and CRM integration.$q$, $q$B2B marketing and demand generation teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Product demos and sales enablement$q$, $q$Sales teams use Livestorm for live product demonstrations with engagement tools like polls and Q&A to qualify prospects.$q$, $q$Sales and customer-facing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Customer onboarding and training$q$, $q$HR and customer education teams use Livestorm's on-demand and recorded event features for scalable onboarding and training sessions.$q$, $q$HR, L&D and customer education teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 30 attendees per session","20-minute session limit","Unlimited events and moderators","Landing page builder and email customization"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Pro$q$, $q$~$2.50-3.00 per attendee credit$q$, $q$Annual (attendee credits)$q$, NULL, $q$["Up to 3,000 live attendees per event","4-hour session length","Unlimited events, recordings and team members","HubSpot and Zapier integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Contact sales$q$, NULL, $q$["Up to 12-hour sessions","Salesforce, Marketo, Pardot and Microsoft Dynamics integrations","Custom analytics and reporting","Dedicated Customer Success Manager"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Livestorm is a browser-based webinar and video engagement platform founded in 2016 by Gilles Bertaux and headquartered in Paris, France, with roughly 100 to 120 employees.$q$, $q$It runs entirely in the browser for both hosts and attendees with no downloads or plugins, distinguishing it from legacy desktop-client webinar tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Livestorm bundles registration pages, automated email sequences, live captioning and transcription, in-session engagement tools like polls and Q&A, and AI content repurposing from webinar transcripts.$q$, $q$It integrates with HubSpot and Zapier broadly, and with Salesforce, Marketo, Pardot and Microsoft Dynamics on the Enterprise tier, and holds GDPR and ISO 27001 compliance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dce09c20-9cc8-49b7-8cbd-f9cc75440903', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Livestorm offers a permanent Free plan capped at 20-minute sessions and 30 attendees, while paid tiers use an annually purchased attendee-credit model priced at roughly $2.50-3.00 per credit.$q$, $q$The Pro plan supports up to 3,000 live attendees and 4-hour sessions, while Enterprise adds 12-hour sessions, enterprise CRM integrations and a dedicated Customer Success Manager at custom pricing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Single-Binary Deployment$q$, $q$Compiles to one self-contained executable with no external database required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Rust and Tokio Architecture$q$, $q$Built in Rust with the tokio async runtime for speed and low resource usage.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Cookieless Privacy Model$q$, $q$No cookies, no cross-site tracking and no persistent visitor identifiers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Bot and Crawler Filtering$q$, $q$Automatically filters obvious bots and crawlers from reported traffic.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Page Views and Referrer Tracking$q$, $q$Core analytics dashboard covering page views, visitor groups and referrer sources.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Minimal Infrastructure Footprint$q$, $q$Runs on a cheap VPS, an old Mac Mini or a Raspberry Pi with minimal setup.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Open Source on GitHub$q$, $q$Fully open-source codebase available at explodingcamera/liwan for self-hosting and contribution.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Hosted Demo$q$, $q$A public hosted demo at demo.liwan.dev lets users try the dashboard before self-deploying.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Completely free and open source with no paid tier required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Extremely lightweight, single-binary deployment with no database$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Strong privacy model with no cookies or persistent identifiers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Can run on very low-cost hardware including a Raspberry Pi$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Minimal, focused feature set is easy to understand and operate$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$No managed hosted SaaS option, so operators must self-host and maintain it themselves$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Small, solo-maintained project with no dedicated support team$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Lacks advanced features like funnels, session replay or AI reporting$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Smaller community and ecosystem than more established tools like Plausible$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Documentation and polish are more limited than commercially backed competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$What is Liwan?$q$, $q$Liwan is a lightweight, self-hosted, privacy-first web analytics tool written in Rust that runs as a single binary with no database required.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Is Liwan free?$q$, $q$Yes, Liwan is entirely free and open source; there is no paid managed hosting tier.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Who created Liwan?$q$, $q$Liwan was created by German developer Henry Gressmann, known as explodingcamera, and introduced publicly in 2024.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Does Liwan require a database?$q$, $q$No, Liwan compiles to a single self-contained binary with no external database dependency.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Is Liwan the same as Litlyx?$q$, $q$No, Liwan and Litlyx are separate, unrelated privacy-analytics projects; Liwan is a minimal open-source self-hosted tool while Litlyx is a commercial, AI-augmented product.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$What hardware can run Liwan?$q$, $q$Liwan is lightweight enough to run on a cheap VPS, an old Mac Mini or even a Raspberry Pi.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Self-hosted infrastructure analytics$q$, $q$Developers who already self-host their own applications add Liwan alongside them to track site traffic without adopting a new database-backed stack.$q$, $q$Developers and indie hackers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Low-resource deployments$q$, $q$Teams running services on minimal hardware like a Raspberry Pi or small VPS use Liwan because it needs no database and has a tiny resource footprint.$q$, $q$Homelab operators and small teams with limited infrastructure$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Privacy-first minimal tracking$q$, $q$Privacy-conscious site owners use Liwan to get basic page view and referrer analytics without cookies or persistent visitor identifiers.$q$, $q$Privacy-conscious website owners$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Single-binary deployment, no database required","Page views, visitor groups and referrer tracking","Bot and crawler filtering","Full data ownership on your own infrastructure"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Liwan is a lightweight, self-hosted, privacy-first web analytics tool created by German developer Henry Gressmann and introduced publicly in 2024 as an independent open-source project.$q$, $q$It is written in Rust, compiles to a single self-contained binary with no database dependency, and can run on infrastructure as small as a Raspberry Pi.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Liwan tracks page views, visitor groups and referrers with automatic bot and crawler filtering, while avoiding cookies, cross-site tracking and persistent identifiers.$q$, $q$It deliberately skips advanced product-analytics features like funnels or AI reporting to stay minimal and easy to operate, distinguishing it from feature-rich competitors like Litlyx.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c95b7ac8-c110-41fe-a3fc-2fb5237155d8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Liwan is entirely free and open source; there is no paid managed hosting tier, and the hosted demo exists only to let users try the dashboard before self-deploying.$q$, $q$Operators are responsible for installing, updating and maintaining their own instance, typical of self-hosted open-source software.$q$]::text[], 2);
